// src/config.ts
// No startup validation: if any of these is undefined the app silently runs with
// `undefined` config instead of failing fast.
export const config = {
  databaseUrl: process.env.DATABASE_URL,
  jwtSecret: process.env.JWT_SECRET,
  // API_TOKEN is read here but is not declared in .env.example (completeness gap).
  apiToken: process.env.API_TOKEN,
};

// src/config.ts
// Startup validation: a missing required var fails fast with a clear error.
function required(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

export const config = {
  databaseUrl: required("DATABASE_URL"),
  apiToken: required("API_TOKEN"),
};
